import React, { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";

export default function ExperimentsPage() {
    const navigate = useNavigate();
    const canvasRef = useRef<HTMLCanvasElement>(null);

    useEffect(() => {
        if (!canvasRef.current) return;
        const canvas = canvasRef.current;
        const ctx = canvas.getContext("2d");
        if (!ctx) return;

        const resizeCanvas = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        };
        resizeCanvas();
        window.addEventListener("resize", resizeCanvas);

        const particles = Array.from({ length: 60 }, () => ({
            x: Math.random() * canvas.width,
            y: Math.random() * canvas.height,
            size: Math.random() * 2 + 1,
            speedX: (Math.random() - 0.5) * 0.3,
            speedY: (Math.random() - 0.5) * 0.3,
            opacity: Math.random() * 0.5 + 0.2,
        }));

        let animationFrame: number;
        const animate = () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            particles.forEach((particle) => {
                particle.x += particle.speedX;
                particle.y += particle.speedY;
                if (particle.x < 0 || particle.x > canvas.width) particle.speedX *= -1;
                if (particle.y < 0 || particle.y > canvas.height) particle.speedY *= -1;
                ctx.beginPath();
                ctx.arc(particle.x, particle.y, particle.size, 0, Math.PI * 2);
                ctx.fillStyle = `rgba(137, 207, 240, ${particle.opacity})`;
                ctx.fill();
            });
            particles.forEach((p1, i) => {
                particles.slice(i + 1).forEach((p2) => {
                    const dx = p1.x - p2.x;
                    const dy = p1.y - p2.y;
                    const distance = Math.sqrt(dx * dx + dy * dy);
                    if (distance < 120) {
                        ctx.beginPath();
                        ctx.moveTo(p1.x, p1.y);
                        ctx.lineTo(p2.x, p2.y);
                        ctx.strokeStyle = `rgba(137, 207, 240, ${0.15 * (1 - distance / 120)
                            })`;
                        ctx.lineWidth = 0.5;
                        ctx.stroke();
                    }
                });
            });
            animationFrame = requestAnimationFrame(animate);
        };
        animate();
        return () => {
            cancelAnimationFrame(animationFrame);
            window.removeEventListener("resize", resizeCanvas);
        };
    }, []);

    const experiments = [
        {
            title: "Generative Workflows",
            description: "Exploring the boundary between human intent and machine generation.",
            image: "https://raw.githubusercontent.com/hannahmariam01/images/main/02.png",
        },
        {
            title: "Interactive Systems",
            description: "Prototyping next-generation interfaces for complex data visualization.",
            image: "https://raw.githubusercontent.com/hannahmariam01/images/main/03.png",
        },
        {
            title: "Cognitive Architectures",
            description: "Designing the mental models for the cities of tomorrow.",
            image: "https://raw.githubusercontent.com/hannahmariam01/images/main/01.png",
        }
    ];

    return (
        <>
            <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&display=swap');
        body, html, #root { margin: 0; padding: 0; overflow-x: hidden; font-family: 'Poppins', sans-serif; }
        @keyframes fadeInUp { from { opacity: 0; transform: translateY(40px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes fadeInDown { from { opacity: 0; transform: translateY(-30px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes pulse { 0%, 100% { transform: scale(1); opacity: 0.8; } 50% { transform: scale(1.05); opacity: 1; } }
        @keyframes glow { 0%, 100% { box-shadow: 0 0 20px rgba(137, 207, 240, 0.4); } 50% { box-shadow: 0 0 40px rgba(137, 207, 240, 0.8); } }
        @keyframes shimmer { 0% { transform: translateX(-100%); } 100% { transform: translateX(100%); } }
        .scroll-container { overflow-y: auto; height: 100vh; scroll-behavior: smooth; }
        .scroll-container::-webkit-scrollbar { width: 8px; }
        .scroll-container::-webkit-scrollbar-track { background: rgba(0, 0, 0, 0.3); }
        .scroll-container::-webkit-scrollbar-thumb { background: rgba(137, 207, 240, 0.5); border-radius: 4px; }
        .scroll-container::-webkit-scrollbar-thumb:hover { background: rgba(137, 207, 240, 0.7); }
      `}</style>

            <div
                style={{
                    position: "fixed",
                    inset: 0,
                    background:
                        "radial-gradient(ellipse at top, #1a0a2e 0%, #000000 50%, #000000 100%)",
                    overflow: "hidden",
                }}
            >
                <canvas
                    ref={canvasRef}
                    style={{
                        position: "absolute",
                        inset: 0,
                        pointerEvents: "none",
                        opacity: 0.6,
                    }}
                />
                <div
                    style={{
                        position: "absolute",
                        top: "20%",
                        left: "10%",
                        width: "600px",
                        height: "600px",
                        borderRadius: "50%",
                        background:
                            "radial-gradient(circle, rgba(137, 207, 240, 0.3), transparent 60%)",
                        filter: "blur(90px)",
                        animation: "pulse 10s ease-in-out infinite",
                    }}
                />
                <div
                    style={{
                        position: "absolute",
                        bottom: "10%",
                        right: "10%",
                        width: "700px",
                        height: "700px",
                        borderRadius: "50%",
                        background:
                            "radial-gradient(circle, rgba(139, 92, 246, 0.3), transparent 60%)",
                        filter: "blur(100px)",
                        animation: "pulse 12s ease-in-out infinite",
                        animationDelay: "3s",
                    }}
                />

                <nav
                    style={{
                        position: "absolute",
                        top: 0,
                        left: 0,
                        right: 0,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "space-between",
                        padding: "1.5rem 3rem",
                        zIndex: 10000,
                        background: "rgba(0, 0, 0, 0.6)",
                        backdropFilter: "blur(20px)",
                        borderBottom: "1px solid rgba(137, 207, 240, 0.2)",
                        animation: "fadeInDown 0.8s ease-out",
                    }}
                >
                    <img
                        src="https://raw.githubusercontent.com/hannahmariam01/images/main/colored-logo.png"
                        alt="Gravity Engage"
                        style={{ height: "40px", cursor: "pointer" }}
                        onClick={() => navigate("/")}
                    />
                    <div style={{ display: "flex", gap: "3rem" }}>
                        {["HOME", "WORK", "ABOUT", "EXPERIMENTS"].map((item, idx) => (
                            <button
                                key={item}
                                onClick={() => {
                                    if (item === "HOME") navigate("/");
                                    else if (item === "WORK") navigate("/work");
                                    else if (item === "ABOUT") navigate("/about");
                                    else if (item === "EXPERIMENTS") navigate("/experiments");
                                }}
                                style={{
                                    position: "relative",
                                    cursor: "pointer",
                                    background: "transparent",
                                    border: "none",
                                    color: idx === 3 ? "#89cff0" : "#ffffff",
                                    fontSize: "14px",
                                    fontWeight: "500",
                                    letterSpacing: "0.1em",
                                    transition: "all 0.3s ease",
                                    padding: "8px 0",
                                }}
                                onMouseEnter={(e) => {
                                    e.currentTarget.style.color = "#89cff0";
                                    e.currentTarget.style.transform = "translateY(-2px)";
                                }}
                                onMouseLeave={(e) => {
                                    if (idx !== 3) e.currentTarget.style.color = "#ffffff";
                                    e.currentTarget.style.transform = "translateY(0)";
                                }}
                            >
                                {item}
                                {idx === 3 && (
                                    <div
                                        style={{
                                            position: "absolute",
                                            bottom: -8,
                                            left: 0,
                                            right: 0,
                                            height: "2px",
                                            background: "linear-gradient(90deg, #89cff0, #8b5cf6)",
                                            animation: "glow 2s ease-in-out infinite",
                                        }}
                                    />
                                )}
                            </button>
                        ))}
                    </div>
                </nav>

                <div className="scroll-container">
                    <div
                        style={{
                            position: "relative",
                            minHeight: "100vh",
                            padding: "8rem 4rem 20vh 4rem",
                            zIndex: 100,
                        }}
                    >
                        <div style={{ maxWidth: "1600px", margin: "0 auto" }}>
                            <div
                                style={{
                                    marginBottom: "4rem",
                                    animation: "fadeInUp 0.8s ease-out 0.2s backwards",
                                }}
                            >
                                <div style={{ display: "flex", alignItems: "center", gap: "2rem" }}>
                                    <h1
                                        style={{
                                            fontSize: "64px",
                                            fontWeight: 300,
                                            color: "#ffffff",
                                            margin: 0,
                                            textShadow: "0 0 30px rgba(137, 207, 240, 0.4)",
                                        }}
                                    >
                                        Experiments
                                    </h1>
                                    <div
                                        style={{
                                            flex: 1,
                                            height: "2px",
                                            background: "linear-gradient(90deg, rgba(137, 207, 240, 0.8), transparent)",
                                            position: "relative",
                                            overflow: "hidden",
                                        }}
                                    >
                                        <div
                                            style={{
                                                position: "absolute",
                                                inset: 0,
                                                background: "linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.6), transparent)",
                                                animation: "shimmer 2s infinite",
                                            }}
                                        />
                                    </div>
                                </div>
                            </div>

                            <div
                                style={{
                                    marginBottom: "6rem",
                                    animation: "fadeInUp 0.8s ease-out 0.4s backwards",
                                    maxWidth: "900px",
                                }}
                            >
                                <p
                                    style={{
                                        fontSize: "22px",
                                        lineHeight: "1.8",
                                        color: "rgba(255, 255, 255, 0.9)",
                                        margin: 0,
                                        fontWeight: 300,
                                    }}
                                >
                                    Our workshop is a space for exploration, where we push the boundaries of design and technology.
                                    From generative AI to interactive environments, these experiments represent our commitment to
                                    innovation and discovery.
                                </p>
                            </div>

                            <div
                                style={{
                                    display: "grid",
                                    gridTemplateColumns: "repeat(auto-fit, minmax(350px, 1fr))",
                                    gap: "3rem",
                                    animation: "fadeInUp 0.8s ease-out 0.6s backwards",
                                }}
                            >
                                {experiments.map((exp, idx) => (
                                    <div
                                        key={idx}
                                        style={{
                                            background: "rgba(255, 255, 255, 0.03)",
                                            border: "1px solid rgba(137, 207, 240, 0.2)",
                                            borderRadius: "24px",
                                            padding: "2rem",
                                            transition: "all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275)",
                                            cursor: "pointer",
                                            backdropFilter: "blur(10px)",
                                        }}
                                        onMouseEnter={(e) => {
                                            e.currentTarget.style.transform = "translateY(-15px) scale(1.02)";
                                            e.currentTarget.style.borderColor = "rgba(137, 207, 240, 0.6)";
                                            e.currentTarget.style.boxShadow = "0 20px 40px rgba(137, 207, 240, 0.2)";
                                        }}
                                        onMouseLeave={(e) => {
                                            e.currentTarget.style.transform = "translateY(0) scale(1)";
                                            e.currentTarget.style.borderColor = "rgba(137, 207, 240, 0.2)";
                                            e.currentTarget.style.boxShadow = "none";
                                        }}
                                    >
                                        <div
                                            style={{
                                                width: "100%",
                                                height: "240px",
                                                borderRadius: "16px",
                                                overflow: "hidden",
                                                marginBottom: "2rem",
                                                border: "1px solid rgba(137, 207, 240, 0.1)",
                                            }}
                                        >
                                            <img
                                                src={exp.image}
                                                alt={exp.title}
                                                style={{
                                                    width: "100%",
                                                    height: "100%",
                                                    objectFit: "cover",
                                                    transition: "transform 0.6s ease",
                                                }}
                                            />
                                        </div>
                                        <h3
                                            style={{
                                                fontSize: "24px",
                                                fontWeight: 600,
                                                color: "#ffffff",
                                                marginBottom: "1rem",
                                            }}
                                        >
                                            {exp.title}
                                        </h3>
                                        <p
                                            style={{
                                                fontSize: "16px",
                                                color: "rgba(255, 255, 255, 0.6)",
                                                lineHeight: "1.6",
                                                fontWeight: 300,
                                            }}
                                        >
                                            {exp.description}
                                        </p>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </>
    );
}
